import{_ as a,o,c as r,ag as e}from"./chunks/framework.Bgwu_dgr.js";const c=JSON.parse('{"title":"전문성의 공백","description":"","frontmatter":{},"headers":[],"relativePath":"topics/expertise-gap.md","filePath":"topics/expertise-gap.md","lastUpdated":null}'),s={name:"topics/expertise-gap.md"};function n(l,t,i,p,h,g){return o(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="전문성의-공백" tabindex="-1">전문성의 공백 <a class="header-anchor" href="#전문성의-공백" aria-label="Permalink to &quot;전문성의 공백&quot;">​</a></h1><p>발표는 선언으로 시작하지 않는다. 하나의 관찰로 시작한다. 에이전트는 2025년 한 해 동안 놀라울 정도로 널리 쓰이게 되었다. Claude Code, Cursor, Copilot, 그리고 수많은 도메인 에이전트가 일상이 되었다. 그런데 -- 실무에 투입해 보면 여전히 뭔가 부족하다. 그 &#39;뭔가&#39;를 Zhang과 Murag은 **전문성(expertise)**이라 부른다.</p><h2 id="세무-전문가-barry-수학-천재-mahesh" tabindex="-1">세무 전문가 Barry, 수학 천재 Mahesh <a class="header-anchor" href="#세무-전문가-barry-수학-천재-mahesh" aria-label="Permalink to &quot;세무 전문가 Barry, 수학 천재 Mahesh&quot;">​</a></h2><p>발표 초반에 Zhang이 던지는 비유는 이 전체 발표의 축소판이다.</p><blockquote><p>세무 코드 200페이지를 앞에 두고 있다고 해보자. 당신에겐 두 사람이 있다. 한 명은 300 IQ의 수학 천재 Mahesh. 다른 한 명은 20년 경력의 세무 전문가 Barry. 어느 쪽을 고르겠는가?</p><p>나는 매번 Barry를 고르겠다.</p></blockquote><p>세무 코드를 푸는 데 필요한 것은 더 높은 지능이 아니라, 그 영역의 <strong>패턴과 예외를 몸으로 아는 축적된 경험</strong>이다. 이 비유가 에이전트 설계에 주는 함의는 분명하다. 에이전트를 더 똑똑하게 만드는 것(=더 큰 모델, 더 긴 컨텍스트)은 이 공백을 메우지 못한다. 오히려 <strong>전문성을 에이전트에게 전달하는 방법</strong>이 필요하다.</p><h2 id="지능과-전문성은-다른-층위에-있다" tabindex="-1">지능과 전문성은 다른 층위에 있다 <a class="header-anchor" href="#지능과-전문성은-다른-층위에-있다" aria-label="Permalink to &quot;지능과 전문성은 다른 층위에 있다&quot;">​</a></h2><p>발표자들은 이 구분을 반복적으로 강조한다.</p><ul><li><strong>지능(Intelligence)</strong> -- 문제를 이해하고, 추론하고, 새로운 상황에 적응하는 능력. 모델 학습으로 길러진다.</li><li><strong>전문성(Expertise)</strong> -- 특정 도메인의 축적된 절차적 지식. 수많은 케이스를 거치며 만들어진 &quot;실무의 감&quot;.</li></ul><p>오늘날의 프론티어 모델은 지능에서는 이미 많은 인간을 능가한다. 그러나 실무에서는 <strong>중요한 맥락이 앞에 놓여 있지 않기 때문에</strong> 헛된 일을 반복하거나 정답 근처에서 실패한다. 한 번도 본 적 없는 조직의 코드 스타일, 특정 회사의 이상한 내부 도구 사용법, 법무팀이 매달 처리하는 템플릿의 미묘한 규칙 -- 이런 것들은 모델 파라미터가 아니라 <strong>외부에서 주입되어야 한다.</strong></p><h2 id="왜-프롬프트나-미세조정은-답이-아닌가" tabindex="-1">왜 프롬프트나 미세조정은 답이 아닌가 <a class="header-anchor" href="#왜-프롬프트나-미세조정은-답이-아닌가" aria-label="Permalink to &quot;왜 프롬프트나 미세조정은 답이 아닌가&quot;">​</a></h2><p>맥락을 주입하는 기존 방법들도 있다. 길고 정교한 시스템 프롬프트, RAG, 도메인 특화 미세조정(fine-tuning). 그러나 각각에는 한계가 있다.</p><ul><li><strong>긴 프롬프트</strong> -- 매번 모든 맥락을 컨텍스트에 욱여넣으면 비용과 지연이 커지고, 무관한 정보가 모델을 혼란시킨다.</li><li><strong>RAG</strong> -- 검색 결과의 질에 의존하며, 절차적 지식(how)보다 사실적 지식(what)에 유리하다.</li><li><strong>미세조정</strong> -- 비용이 높고, 업데이트가 느리며, 조직의 일상적 변화에 따라가기 어렵다.</li></ul><p>스킬이 해결하려는 문제는 바로 여기다. <strong>절차적 지식(how-to)을, 저렴하고, 빠르게 수정 가능하며, 필요할 때만 불러올 수 있는 형태로</strong> 에이전트에 공급하는 것.</p><h2 id="기존-에이전트-도구의-한계" tabindex="-1">기존 에이전트 도구의 한계 <a class="header-anchor" href="#기존-에이전트-도구의-한계" aria-label="Permalink to &quot;기존 에이전트 도구의 한계&quot;">​</a></h2><p>발표자들은 기존의 &quot;도구(tool) 호출&quot; 방식에도 근본적 한계가 있다고 지적한다. 에이전트에게 <code>calculate_tax</code> 같은 도구를 정의해 주는 접근은 두 가지 문제를 낳는다.</p><ol><li><strong>모호성</strong> -- 도구의 시그니처와 짧은 설명만으로는 세세한 동작을 완전히 기술할 수 없다. 엣지 케이스에서 에이전트가 잘못 호출한다.</li><li><strong>수정 불가능성</strong> -- 도구가 기대와 다르게 작동해도 에이전트는 그것을 고쳐쓸 수 없다. 도구는 블랙박스다.</li></ol><p>반면 스킬 안의 스크립트는 **자기 문서화(self-documenting)**되어 있고, 필요하면 에이전트가 <strong>그 자리에서 읽고 수정</strong>할 수 있다. 코드는 텍스트이기 때문이다. 이 점이 스킬의 설계를 &quot;도구&quot;가 아닌 &quot;스크립트&quot;로 기울게 한 결정적인 이유다.</p><h2 id="공백을-메우는-방식으로서의-스킬" tabindex="-1">공백을 메우는 방식으로서의 스킬 <a class="header-anchor" href="#공백을-메우는-방식으로서의-스킬" aria-label="Permalink to &quot;공백을 메우는 방식으로서의 스킬&quot;">​</a></h2><p>Zhang과 Murag이 전하는 결론은 명확하다. 공백은 모델이 더 똑똑해져서 사라지지 않는다. 공백은 <strong>조직이 자기 전문성을 형태 있는 산출물로 바꿔 에이전트에게 공급할 때</strong> 메워진다. 그 산출물이 바로 스킬이다.</p><p>세무 전문가 Barry가 20년간 축적한 판단들, 사내 개발팀이 지난 3년간 정착시킨 배포 체크리스트, 법무팀이 분기마다 손보는 계약서 리뷰 규칙 -- 이 모든 것이 이제 <strong>에이전트가 필요할 때 꺼내 쓰는 파일</strong>이 된다.</p><p>발표가 전하는 전환의 요지는, 결국 이 한 문장으로 압축된다.</p><blockquote><p>에이전트를 더 똑똑하게 만드는 것은 더 이상 한계 효용이 크지 않다. 지금 필요한 것은 <strong>에이전트에게 전문성을 공급하는 시스템</strong>이다.</p></blockquote>',23)])])}const d=a(s,[["render",n]]);export{c as __pageData,d as default};
